import type { VercelRequest, VercelResponse } from '@vercel/node';

const SUPABASE_URL = 'https://ihcnwuaxcylbivuvzubz.supabase.co';

export default async function handler(req: VercelRequest, res: VercelResponse) {
  // CORS preflight
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, PATCH, DELETE, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'authorization, apikey, content-type, prefer, x-client-info, accept, accept-profile, content-profile, x-upsert');

  if (req.method === 'OPTIONS') {
    return res.status(200).end();
  }

  // Path build karo
  const pathSegments = Array.isArray(req.query.path)
    ? req.query.path
    : [req.query.path || ''];
  const path = pathSegments.join('/');

  // Query string build karo (path param chhod ke)
  const queryParams = new URLSearchParams();
  Object.entries(req.query).forEach(([key, value]) => {
    if (key === 'path') return;
    if (Array.isArray(value)) {
      value.forEach(v => queryParams.append(key, v));
    } else if (value !== undefined) {
      queryParams.set(key, value);
    }
  });

  const qs = queryParams.toString();
  const targetUrl = `${SUPABASE_URL}/${path}${qs ? '?' + qs : ''}`;

  // Headers forward karo
  const forwardHeaders: Record<string, string> = {};
  const allowed = [
    'authorization', 'apikey', 'content-type', 'prefer',
    'x-client-info', 'accept', 'accept-profile',
    'content-profile', 'x-upsert', 'range',
  ];
  allowed.forEach(h => {
    const val = req.headers[h];
    if (val) forwardHeaders[h] = Array.isArray(val) ? val[0] : val;
  });

  // Body
  let body: string | undefined;
  if (req.method !== 'GET' && req.method !== 'HEAD') {
    body = typeof req.body === 'string' ? req.body : JSON.stringify(req.body);
  }

  try {
    const response = await fetch(targetUrl, {
      method: req.method || 'GET',
      headers: forwardHeaders,
      body,
    });

    const text = await response.text();

    // Response headers
    const contentType = response.headers.get('content-type');
    if (contentType) res.setHeader('Content-Type', contentType);

    const exposedHeaders = response.headers.get('content-range');
    if (exposedHeaders) res.setHeader('Content-Range', exposedHeaders);

    return res.status(response.status).send(text);
  } catch (err) {
    console.error('Proxy error:', err);
    return res.status(500).json({ error: 'Proxy failed', message: String(err) });
  }
}
